// src/components/Common/cvsection.js
import React, { useState } from "react";

export default function CVSection({ workerInfo, isEditable = false, onSave }) {
  const [showEditModal, setShowEditModal] = useState(false);
  const [editedInfo, setEditedInfo] = useState(null);
  const [newSkill, setNewSkill] = useState("");

  // فتح المودال - نسخ البيانات مرة واحدة
  const openModal = () => {
    setEditedInfo({
      name: workerInfo.name,
      role: workerInfo.role,
      experience: workerInfo.experience,
      skills: [...(workerInfo.skills || [])],
      bio: workerInfo.bio,
      email: workerInfo.email,
      phone: workerInfo.phone,
      location: workerInfo.location,
      languages: [...(workerInfo.languages || [])]
    });
    setShowEditModal(true);
  };

  // إغلاق المودال
  const closeModal = () => {
    setShowEditModal(false);
    setEditedInfo(null);
    setNewSkill("");
  };

  // إضافة مهارة
  const addSkill = () => {
    if (newSkill.trim() && editedInfo && !editedInfo.skills.includes(newSkill.trim())) {
      setEditedInfo(prev => ({
        ...prev,
        skills: [...prev.skills, newSkill.trim()]
      }));
      setNewSkill("");
    }
  };

  // حذف مهارة
  const removeSkill = (skillToRemove) => {
    setEditedInfo(prev => ({
      ...prev,
      skills: prev.skills.filter(skill => skill !== skillToRemove)
    }));
  };

  // حفظ التغييرات
  const handleSave = () => {
    if (onSave && editedInfo) {
      onSave(editedInfo);
    }
    closeModal();
  };

  const styles = `
    .cv-container { text-align: center; }
    .cv-icon { font-size: 4rem; margin-bottom: 1rem; }
    .cv-name { color: white !important; font-size: 1.5rem; font-weight: bold; margin-bottom: 0.5rem; }
    .cv-role { color: #22c55e !important; margin-bottom: 1rem; }
    .cv-section-title { color: white !important; font-size: 1.2rem; font-weight: bold; margin-top: 1.5rem; margin-bottom: 0.75rem; }
    .cv-text { color: rgba(255,255,255,0.85) !important; line-height: 1.5; }
    .cv-contact { color: rgba(255,255,255,0.8) !important; margin: 0.25rem 0; }
    .skill-tag { display: inline-block; padding: 5px 12px; background: rgba(34,197,94,0.2); border-radius: 20px; font-size: 12px; margin: 3px; color: #4ade80 !important; border: 1px solid rgba(34,197,94,0.4); }
    .skill-tag-remove { background: none; border: none; color: #ef4444 !important; cursor: pointer; font-size: 14px; margin-left: 6px; padding: 0; }
    .skill-tag-remove:hover { color: #ff6666 !important; }
    .btn-primary { background: linear-gradient(135deg, #22c55e, #15803d); border: none; padding: 10px 20px; border-radius: 25px; color: white !important; font-weight: bold; cursor: pointer; transition: all 0.2s; width: 100%; }
    .btn-primary:hover { transform: scale(1.02); filter: brightness(1.1); }
    .btn-add { background: linear-gradient(135deg, #22c55e, #15803d); border: none; padding: 10px 15px; border-radius: 25px; color: white !important; font-weight: bold; cursor: pointer; transition: all 0.2s; white-space: nowrap; }
    .btn-add:hover { transform: scale(1.02); }
    .btn-cancel { background: linear-gradient(135deg, #6b7280, #4b5563); border: none; padding: 10px 20px; border-radius: 25px; color: white !important; font-weight: bold; cursor: pointer; transition: all 0.2s; width: 100%; margin-top: 10px; }
    .btn-cancel:hover { transform: scale(1.02); filter: brightness(1.1); }
    .modal-overlay-cv {
      position: fixed !important;
      top: 0 !important;
      left: 0 !important;
      right: 0 !important;
      bottom: 0 !important;
      background: rgba(0, 0, 0, 0.95) !important;
      backdrop-filter: blur(12px) !important;
      z-index: 20000 !important;
      display: flex !important;
      align-items: center !important;
      justify-content: center !important;
      animation: fadeIn 0.3s ease !important;
    }
    .modal-content-cv {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 550px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
      animation: slideUp 0.4s ease;
    }
    .modal-content-cv::-webkit-scrollbar { width: 6px; }
    .modal-content-cv::-webkit-scrollbar-track { background: rgba(255,255,255,0.1); border-radius: 10px; }
    .modal-content-cv::-webkit-scrollbar-thumb { background: #22c55e; border-radius: 10px; }
    .close-btn { float: right; background: none; border: none; color: white !important; font-size: 24px; cursor: pointer; transition: all 0.2s; }
    .close-btn:hover { transform: scale(1.1); color: #ef4444 !important; }
    .modal-title { color: white !important; font-size: 1.5rem; font-weight: bold; margin-bottom: 1rem; text-align: center; }
    .modal-icon { font-size: 3rem; margin-bottom: 0.5rem; text-align: center; }
    .form-group { margin-bottom: 1rem; }
    .form-label { display: block; color: white !important; font-size: 0.85rem; margin-bottom: 0.5rem; }
    .form-input { width: 100%; padding: 12px; background: rgba(255,255,255,0.1); border: 1px solid rgba(34,197,94,0.3); border-radius: 15px; color: white !important; font-size: 0.9rem; transition: all 0.2s; box-sizing: border-box; }
    .form-input:focus { outline: none; border-color: #22c55e; box-shadow: 0 0 10px rgba(34,197,94,0.3); }
    textarea.form-input { resize: vertical; font-family: inherit; }
    .skills-container { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 12px; }
    .skill-item { display: inline-flex; align-items: center; gap: 6px; background: rgba(34,197,94,0.15); border-radius: 20px; padding: 5px 12px; color: #4ade80 !important; font-size: 12px; border: 1px solid rgba(34,197,94,0.3); }
    .add-skill-row { display: flex; gap: 10px; align-items: center; }
    .add-skill-input { flex: 1; padding: 10px; background: rgba(255,255,255,0.1); border: 1px solid rgba(34,197,94,0.3); border-radius: 15px; color: white !important; font-size: 0.9rem; }
    @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
    @keyframes slideUp { from { opacity: 0; transform: translateY(30px); } to { opacity: 1; transform: translateY(0); } }
    @media (max-width: 480px) { .modal-content-cv { padding: 20px; } .add-skill-row { flex-direction: column; } .btn-add { width: 100%; } }
  `;

  // عرض CV (وضع القراءة)
  const CVContent = () => (
    <div className="cv-container">
      <div className="cv-icon">👩‍💻</div>
      <h2 className="cv-name">{workerInfo.name}</h2>
      <p className="cv-role">{workerInfo.role}</p>
      <div className="text-left">
        <h3 className="cv-section-title">📋 Profil</h3>
        <p className="cv-text">{workerInfo.bio}</p>
        <h3 className="cv-section-title">💪 Compétences</h3>
        <div className="flex flex-wrap gap-2">
          {workerInfo.skills?.map((skill, i) => (<span key={i} className="skill-tag">{skill}</span>))}
        </div>
        <h3 className="cv-section-title">📞 Contact</h3>
        <p className="cv-contact">📧 {workerInfo.email}</p>
        <p className="cv-contact">📱 {workerInfo.phone}</p>
        <p className="cv-contact">📍 {workerInfo.location}</p>
        <h3 className="cv-section-title">🎓 Expérience</h3>
        <p className="cv-text">{workerInfo.experience}</p>
        {workerInfo.languages && workerInfo.languages.length > 0 && (
          <>
            <h3 className="cv-section-title">🌐 Langues</h3>
            <div className="flex flex-wrap gap-2">
              {workerInfo.languages.map((lang, i) => (<span key={i} className="skill-tag">{lang}</span>))}
            </div>
          </>
        )}
      </div>
      {isEditable && (
        <button onClick={openModal} className="btn-primary mt-4">✏️ Modifier CV</button>
      )}
    </div>
  );

  // مودال التعديل
  const EditModal = () => {
    if (!editedInfo) return null;
    
    return (
      <div className="modal-overlay-cv" onClick={closeModal}>
        <div className="modal-content-cv" onClick={(e) => e.stopPropagation()}>
          <button onClick={closeModal} className="close-btn">✕</button>
          <div className="modal-icon">✏️</div>
          <h2 className="modal-title">Modifier le CV</h2>
          
          <div className="form-group">
            <label className="form-label">👤 Nom complet</label>
            <input type="text" className="form-input" value={editedInfo.name} onChange={(e) => setEditedInfo(prev => ({ ...prev, name: e.target.value }))} />
          </div>
          
          <div className="form-group">
            <label className="form-label">💼 Titre du poste</label>
            <input type="text" className="form-input" value={editedInfo.role} onChange={(e) => setEditedInfo(prev => ({ ...prev, role: e.target.value }))} />
          </div>
          
          <div className="form-group">
            <label className="form-label">📧 Email</label>
            <input type="email" className="form-input" value={editedInfo.email} onChange={(e) => setEditedInfo(prev => ({ ...prev, email: e.target.value }))} />
          </div>
          
          <div className="form-group">
            <label className="form-label">📱 Téléphone</label>
            <input type="tel" className="form-input" value={editedInfo.phone} onChange={(e) => setEditedInfo(prev => ({ ...prev, phone: e.target.value }))} />
          </div>
          
          <div className="form-group">
            <label className="form-label">📍 Localisation</label>
            <input type="text" className="form-input" value={editedInfo.location} onChange={(e) => setEditedInfo(prev => ({ ...prev, location: e.target.value }))} />
          </div>
          
          <div className="form-group">
            <label className="form-label">📝 Bio</label>
            <textarea className="form-input" rows="3" value={editedInfo.bio} onChange={(e) => setEditedInfo(prev => ({ ...prev, bio: e.target.value }))} />
          </div>
          
          <div className="form-group">
            <label className="form-label">🎓 Expérience</label>
            <input type="text" className="form-input" value={editedInfo.experience} onChange={(e) => setEditedInfo(prev => ({ ...prev, experience: e.target.value }))} />
          </div>
          
          <div className="form-group">
            <label className="form-label">🌐 Langues (séparées par des virgules)</label>
            <input type="text" className="form-input" value={editedInfo.languages?.join(", ") || ""} onChange={(e) => setEditedInfo(prev => ({ ...prev, languages: e.target.value.split(",").map(l => l.trim()) }))} />
          </div>
          
          <div className="form-group">
            <label className="form-label">💪 Compétences</label>
            <div className="skills-container">
              {editedInfo.skills?.map((skill, i) => (
                <span key={i} className="skill-item">
                  {skill}
                  <button onClick={() => removeSkill(skill)} className="skill-tag-remove">✕</button>
                </span>
              ))}
            </div>
            <div className="add-skill-row">
              <input type="text" className="add-skill-input" placeholder="Ajouter une compétence..." value={newSkill} onChange={(e) => setNewSkill(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && addSkill()} />
              <button onClick={addSkill} className="btn-add">+ Ajouter</button>
            </div>
          </div>
          
          <button onClick={handleSave} className="btn-primary mt-4">💾 Enregistrer</button>
          <button onClick={closeModal} className="btn-cancel mt-2">❌ Annuler</button>
        </div>
      </div>
    );
  };

  return (
    <>
      <style>{styles}</style>
      <CVContent />
      {showEditModal && <EditModal />}
    </>
  );
}
